@@ -273,14 +273,50 @@ pub fn build(b: *std.Build) void {
         .flags = quickjs_wasm_flags,
     });

-    // Add frozen_functions.c (optimized C for self-recursive functions)
+    // Add frozen_functions (optimized C for self-recursive functions)
     // Generated by edgebox-freeze, provides frozen_init() to hot-swap slow JS functions
     // All frozen functions stay in WASM/AOT (sandboxed) - no host exports
     // SHARED location - only changes when opcode handlers or polyfills change
-    wasm_static_exe.root_module.addCSourceFile(.{
-        .file = .{ .cwd_relative = "zig-out/cache/frozen_functions.c" },
-        .flags = quickjs_wasm_flags,
-    });
+    //
+    // Use pre-compiled .o if available (saves ~18min compile time)
+    // Run ./scripts/build-frozen.sh to pre-compile
+    const frozen_o_path = "zig-out/cache/frozen_functions.o";
+    const frozen_c_path = "zig-out/cache/frozen_functions.c";
+    const frozen_hash_path = "zig-out/cache/frozen_functions.sha256";
+
+    const use_precompiled = blk: {
+        // Check if .o and .sha256 exist
+        const o_file = std.fs.cwd().openFile(frozen_o_path, .{}) catch break :blk false;
+        defer o_file.close();
+        const hash_file = std.fs.cwd().openFile(frozen_hash_path, .{}) catch break :blk false;
+        defer hash_file.close();
+        const c_file = std.fs.cwd().openFile(frozen_c_path, .{}) catch break :blk false;
+        defer c_file.close();
+
+        // Read stored hash
+        var stored_hash: [64]u8 = undefined;
+        const hash_len = hash_file.readAll(&stored_hash) catch break :blk false;
+        if (hash_len < 64) break :blk false;
+
+        // Compute current hash of .c file (simplified: check file size as proxy)
+        // Full hash check is done by build-frozen.sh script
+        const c_stat = c_file.stat() catch break :blk false;
+        const o_stat = o_file.stat() catch break :blk false;
+
+        // Use .o if it's newer than .c (basic staleness check)
+        break :blk o_stat.mtime >= c_stat.mtime;
+    };
+
+    if (use_precompiled) {
+        // Use pre-compiled object file (fast!)
+        wasm_static_exe.root_module.addObjectFile(.{ .cwd_relative = frozen_o_path });
+    } else {
+        // Fall back to compiling from source (slow, ~18min)
+        wasm_static_exe.root_module.addCSourceFile(.{
+            .file = .{ .cwd_relative = frozen_c_path },
+            .flags = quickjs_wasm_flags,
+        });
+    }

     // NOTE: native_bindings.c is NOT included - Zig's wasm_main_static.zig has complete
